    private static OriginalRecipe r(String key, Kind kind, String research, String resultExpression, String catalystExpression, String instability, String[] aspectCosts, String[] components, String[] pattern, String sourceMethod) {
        return new OriginalRecipe(key, kind, research, resultExpression, catalystExpression, instability, aspectCosts, components, pattern, sourceMethod);
    }

    private static Map<String, OriginalRecipe> indexByKey(List<OriginalRecipe> recipes) {
        Map<String, OriginalRecipe> map = new LinkedHashMap<>();
        for (OriginalRecipe recipe : recipes) {
            map.put(recipe.key(), recipe);
            map.put(recipe.key().toLowerCase(Locale.ROOT), recipe);
        }
        return Collections.unmodifiableMap(map);
    }

    public static List<OriginalRecipe> all() { return ALL; }

    public static OriginalRecipe byKey(String key) {
        if (key == null || key.isBlank()) return null;
        OriginalRecipe direct = BY_KEY.get(key);
        if (direct != null) return direct;
        return BY_KEY.get(key.toLowerCase(Locale.ROOT));
    }

    public static List<OriginalRecipe> byResearch(String research) {
        if (research == null || research.isBlank()) return List.of();
        String needle = research.toLowerCase(Locale.ROOT);
        List<OriginalRecipe> matches = new ArrayList<>();
        for (OriginalRecipe recipe : ALL) {
            if (recipe.research().equalsIgnoreCase(research) || recipe.key().toLowerCase(Locale.ROOT).contains(needle)) {
                matches.add(recipe);
            }
        }
        return Collections.unmodifiableList(matches);
    }

    public static int count(Kind kind) {
        int c = 0;
        for (OriginalRecipe recipe : ALL) if (recipe.kind() == kind) c++;
        return c;
    }
